+Poco::JSON::Object makeTimeInterval(bool valid, int64_t time, int64_t resolution)
+{
+  Poco::JSON::Object obj;
+  obj.set("valid", valid);
+  obj.set("time", time);
+  obj.set("resolution", resolution);
